window.cart=[];window.addToCart=function(product){window.cart.push(product);frappe.show_alert({message:`${product.product_name} added to cart`,indicator:"green"});console.log("Cart:",window.cart);};window.searchProducts=function(){const search=document.getElementById("search-box").value.toLowerCase();const cards=document.querySelectorAll(".product-card");cards.forEach(card=>{const title=card.querySelector(".product-title").innerText.toLowerCase();if(title.includes(search)){card.style.display="block";}else{card.style.display="none";}});};